/**
 * @fileoverview Loki Wiki Browser - R5 auto-wiki + cited codebase Q&A panel
 * (Loki's answer to Devin DeepWiki). Browses the per-project wiki generated by
 * `loki wiki generate` (GET /api/wiki, /api/wiki/{section}) and runs the
 * grounded Q&A flow (POST /api/wiki/ask). Every answer and section shows
 * file:line citations that point at real source code.
 *
 * @example
 * <loki-wiki-browser api-url="http://localhost:57374" theme="dark"></loki-wiki-browser>
 */

import { LokiElement } from '../core/loki-theme.js';
import { getApiClient } from '../core/loki-api-client.js';

/** @type {Array<{id: string, label: string}>} Wiki section tabs plus the Ask tab. */
const TABS = [
  { id: 'overview', label: 'Overview' },
  { id: 'architecture', label: 'Architecture' },
  { id: 'modules', label: 'Key Modules' },
  { id: 'data-flow', label: 'Data Flow' },
  { id: 'ask', label: 'Ask' },
];

/**
 * @class LokiWikiBrowser
 * @extends LokiElement
 * @property {string} api-url - API base URL (default: window.location.origin)
 * @property {string} theme - 'light' or 'dark'
 */
export class LokiWikiBrowser extends LokiElement {
  static get observedAttributes() {
    return ['api-url', 'theme'];
  }

  constructor() {
    super();
    this._activeTab = 'overview';
    this._loading = false;
    this._error = null;
    this._api = null;
    this._meta = null; // GET /api/wiki
    this._sectionCache = {}; // id -> {title, body, citations}
    // Ask state
    this._question = '';
    this._answer = null;
    this._asking = false;
    this._askError = null;
  }

  connectedCallback() {
    super.connectedCallback();
    this._setupApi();
    this._loadMeta();
  }

  attributeChangedCallback(name, oldValue, newValue) {
    if (name === 'api-url' && this._api) {
      this._api.baseUrl = newValue;
    }
  }

  _setupApi() {
    const apiUrl = this.getAttribute('api-url') || window.location.origin;
    this._api = getApiClient({ baseUrl: apiUrl });
  }

  async _loadMeta() {
    this._loading = true;
    this._error = null;
    this.render();
    try {
      this._meta = await this._api._get('/api/wiki');
    } catch (e) {
      this._error = (e && e.message) ? e.message : 'Failed to load wiki';
    } finally {
      this._loading = false;
      this.render();
      // If the user clicked a section tab during the meta load race (on a
      // generated repo, the gate in _selectTab skipped the fetch because _meta
      // was not yet resolved), load that section now so it does not stay stuck
      // on "Loading...". Only for an active, uncached section tab.
      const t = this._activeTab;
      if (this._meta && this._meta.generated &&
          (t === 'architecture' || t === 'modules' || t === 'data-flow') &&
          !this._sectionCache[t]) {
        this._loadSection(t).then(() => this.render());
      }
    }
  }

  async _loadSection(id) {
    if (this._sectionCache[id]) {
      return this._sectionCache[id];
    }
    try {
      const data = await this._api._get(`/api/wiki/${encodeURIComponent(id)}`);
      this._sectionCache[id] = data;
      return data;
    } catch (e) {
      this._sectionCache[id] = { error: (e && e.message) || 'load failed' };
      return this._sectionCache[id];
    }
  }

  async _selectTab(id) {
    this._activeTab = id;
    if (id === 'architecture' || id === 'modules' || id === 'data-flow') {
      // Only fetch a section when a wiki actually exists. On a fresh repo the
      // manifest reports generated:false and /api/wiki/{section} would 404,
      // flooding the console with 404s + AbortErrors. Render a friendly
      // not-generated message instead of hitting the network -- but do NOT
      // write it to _sectionCache: the cache is permanent (loadSection returns
      // cached entries and never refetches), so caching here would poison the
      // tab if it was clicked before _meta resolved on a repo that DOES have a
      // wiki. _renderSection reads _meta.generated live to decide.
      if (this._meta && this._meta.generated) {
        this.render(); // show spinner
        await this._loadSection(id);
      } else {
        this.render();
      }
    } else {
      this.render();
    }
  }

  async _ask() {
    const q = (this._question || '').trim();
    if (!q) return;
    this._asking = true;
    this._askError = null;
    this._answer = null;
    this.render();
    try {
      // The ask endpoint shells out to claude (and may rebuild the index on a
      // cold repo), so it can take minutes. Use a 200s client timeout, longer
      // than the server's 180s cap, so the server -- not the client -- decides
      // when to give up. The default 10s would abort with "Request timeout".
      this._answer = await this._api._post('/api/wiki/ask', { question: q },
        { timeout: 200000 });
    } catch (e) {
      this._askError = (e && e.message) ? e.message : 'Ask failed';
    } finally {
      this._asking = false;
      this.render();
    }
  }

  /** Escape untrusted text for safe insertion into HTML. */
  _esc(s) {
    return String(s == null ? '' : s)
      .replace(/&/g, '&amp;')
      .replace(/</g, '&lt;')
      .replace(/>/g, '&gt;')
      .replace(/"/g, '&quot;');
  }

  _renderCitations(citations) {
    if (!citations || !citations.length) return '';
    const items = citations.map((c) =>
      `<li><code>${this._esc(c.file)}:${this._esc(c.line)}</code></li>`
    ).join('');
    return `<div class="cites"><strong>Sources:</strong><ul>${items}</ul></div>`;
  }

  _renderOverview() {
    const m = this._meta;
    if (!m || !m.generated) {
      return `<div class="empty">
        <p>No wiki has been generated for this project yet.</p>
        <p>Run <code>loki wiki generate</code> to build a cited codebase wiki.</p>
      </div>`;
    }
    const secs = (m.sections || []).map((s) =>
      `<li>${this._esc(s.title)} <span class="dim">(${this._esc(s.citation_count)} citations)</span></li>`
    ).join('');
    return `<div class="overview">
      <p><strong>${this._esc(m.project || 'Project')}</strong> wiki -
        ${this._esc(m.file_count || 0)} source files indexed.</p>
      <p class="dim">Generated: ${this._esc(m.generated_at || 'unknown')}</p>
      <ul>${secs}</ul>
    </div>`;
  }

  _renderSection(id) {
    // Live check: if no wiki is generated, show the not-generated message
    // (never cached, so it self-corrects once a wiki exists / _meta resolves).
    if (!this._meta || !this._meta.generated) {
      return `<div class="empty">
        <p>No wiki generated yet.</p>
        <p>Run <code>loki wiki generate</code> to build a cited codebase wiki.</p>
      </div>`;
    }
    const data = this._sectionCache[id];
    if (!data) return `<div class="empty">Loading...</div>`;
    if (data.error) return `<div class="error">${this._esc(data.error)}</div>`;
    return `<div class="section">
      <h3>${this._esc(data.title)}</h3>
      <pre class="body">${this._esc(data.body)}</pre>
      ${this._renderCitations(data.citations)}
    </div>`;
  }

  _renderAsk() {
    let result = '';
    if (this._asking) {
      result = `<div class="empty">Searching the codebase...</div>`;
    } else if (this._askError) {
      result = `<div class="error">${this._esc(this._askError)}</div>`;
    } else if (this._answer) {
      const note = this._answer.note
        ? `<p class="dim">${this._esc(this._answer.note)}</p>` : '';
      result = `<div class="answer">
        <pre class="body">${this._esc(this._answer.answer || '')}</pre>
        ${note}
        ${this._renderCitations(this._answer.citations)}
      </div>`;
    }
    return `<div class="ask">
      <div class="ask-row">
        <input id="wiki-q" type="text" placeholder="Ask about this codebase..."
          value="${this._esc(this._question)}" />
        <button id="wiki-ask-btn">Ask</button>
      </div>
      <p class="dim">Answers are grounded in the indexed codebase and cite real file:line locations.</p>
      ${result}
    </div>`;
  }

  _renderBody() {
    if (this._loading) return `<div class="empty">Loading wiki...</div>`;
    if (this._error) return `<div class="error">${this._esc(this._error)}</div>`;
    switch (this._activeTab) {
      case 'overview': return this._renderOverview();
      case 'architecture': return this._renderSection('architecture');
      case 'modules': return this._renderSection('modules');
      case 'data-flow': return this._renderSection('data-flow');
      case 'ask': return this._renderAsk();
      default: return this._renderOverview();
    }
  }

  render() {
    if (!this.shadowRoot) return;
    const tabs = TABS.map((t) =>
      `<button class="tab ${t.id === this._activeTab ? 'active' : ''}"
        data-tab="${t.id}">${this._esc(t.label)}</button>`
    ).join('');

    this.shadowRoot.innerHTML = `
      <style>
        :host { display: block; font-family: var(--loki-font, system-ui, sans-serif);
          color: var(--loki-fg, #1a1a1a); }
        .tabs { display: flex; gap: 4px; border-bottom: 1px solid var(--loki-border, #ddd);
          margin-bottom: 12px; flex-wrap: wrap; }
        .tab { background: none; border: none; padding: 8px 14px; cursor: pointer;
          font-size: 0.9rem; color: var(--loki-fg-dim, #666); border-bottom: 2px solid transparent; }
        .tab.active { color: var(--loki-accent, #2563eb); border-bottom-color: var(--loki-accent, #2563eb); }
        .body { white-space: pre-wrap; word-break: break-word; font-family: inherit;
          background: var(--loki-bg-alt, #f6f8fa); padding: 12px; border-radius: 6px; }
        .cites { margin-top: 10px; font-size: 0.85rem; }
        .cites ul { margin: 4px 0 0; padding-left: 18px; }
        code { font-family: ui-monospace, monospace; font-size: 0.85em;
          background: var(--loki-bg-alt, #eef); padding: 1px 4px; border-radius: 3px; }
        .dim { color: var(--loki-fg-dim, #888); }
        .empty, .error { padding: 16px; }
        .error { color: var(--loki-danger, #c00); }
        .ask-row { display: flex; gap: 8px; margin-bottom: 8px; }
        #wiki-q { flex: 1; padding: 8px; border: 1px solid var(--loki-border, #ccc);
          border-radius: 6px; font-size: 0.9rem; }
        #wiki-ask-btn { padding: 8px 16px; border: none; border-radius: 6px;
          background: var(--loki-accent, #2563eb); color: #fff; cursor: pointer; }
        h3 { margin-top: 0; }
      </style>
      <div class="tabs">${tabs}</div>
      <div class="content">${this._renderBody()}</div>
    `;

    this.shadowRoot.querySelectorAll('.tab').forEach((btn) => {
      btn.addEventListener('click', () => this._selectTab(btn.dataset.tab));
    });
    const input = this.shadowRoot.getElementById('wiki-q');
    if (input) {
      input.addEventListener('input', (e) => { this._question = e.target.value; });
      input.addEventListener('keydown', (e) => { if (e.key === 'Enter') this._ask(); });
    }
    const askBtn = this.shadowRoot.getElementById('wiki-ask-btn');
    if (askBtn) {
      askBtn.addEventListener('click', () => this._ask());
    }
  }
}

if (!customElements.get('loki-wiki-browser')) {
  customElements.define('loki-wiki-browser', LokiWikiBrowser);
}

export default LokiWikiBrowser;
